{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "At or below 200% of the Federal Poverty Guidelines. For April 1, 2025 - March 31, 2026: 1: $31,300; 2: $42,300; 3: $53,300; 4: $64,300; 5: $75,300; 6: $86,300; 7: $97,300; 8: $108,300. Add $11,000 per additional member beyond 8. Automatic eligibility if receiving SSI or FIP regardless of income[1][3].",
    "asset_limits": "No asset limits mentioned in sources[1][3][4].",
    "other_requirements": ["Must qualify for or receive LIHEAP (Heating Assistance) within the last 12 months in some regions[3]", "Home must be primary residence", "Priority for elderly, disabled, families with children[6][7]"]
  },
  "benefits": {
    "type": "service",
    "value": "Energy efficiency improvements including insulation, sealing air leaks (e.g., blower door-guided infiltration reduction), weather-stripping, caulking, health and safety fixes. Work takes about 5 days by qualified contractors or agency crews during normal business hours (8am-5pm Mon-Fri). No direct dollar amount per home; varies by funding and audit results[3][4][6].",
    "varies_by": "priority_tier|region"
  },
  "application": {
    "methods": ["Contact local Community Action Agency (CAA) year-round by phone, in-person, mail, or online LIHEAP app (Nov-Apr online)[2][6]", "State customer service: 515-281-3861[6]", "Locate local CAA via hhs.iowa.gov or call 515-281-3861 if county not listed[6]"],
    "processing_time": "Agency schedules appointment to take application; eligibility determination after; then placed on priority waiting list. Work scheduled later by contractor (about 5 days total)[4].",
    "waitlist": "Statewide priority list based on prior LIHEAP applicants per county; ~80,000 eligible but only ~2,000 served yearly due to funding. Position on list determines wait; may never be reached[3][4].",
    "forms": ["Weatherization application (also serves as LIHEAP application); no specific form number listed[4]"],
    "documents": ["Social Security number", "Most recent heating/electric bill", "Proof of household gross income (past 3 months or calendar year)", "Agency specifies additional at appointment[4][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered via local Community Action Agencies (CAAs) by county[6]",
    "regional_variations": "Services vary by area, funding, cost limits; different agencies (e.g., Community Action of Southeast Iowa, New Opportunities Inc.); waitlists/priority lists per county; ~50 homes/year in SE Iowa vs. 2,000 statewide[2][3][6]",
    "offices_or_providers": ["Local Community Action Agency per county; find via hhs.iowa.gov or call 515-281-3861[6]"]
  },
  "official_source": "https://hhs.iowa.gov/assistance-programs/housing-rent-assistance/weatherization-assistance",
  "gotchas": ["Applying for WAP also applies you for LIHEAP; high demand leads to long waits or non-service despite eligibility due to priority list position[3][4]", "Must provide home access during work hours; renters may qualify but confirm with local agency[9]", "Eligibility often tied to recent LIHEAP approval, not standalone[3]", "Funding limits homes served (~2,000/year statewide)[4]"],
  "data_shape_notes": "Eligibility prioritized via county LIHEAP applicant lists from prior year; services vary by local agency funding/region; no age requirement but priority for elderly"
}

{
  "name": "Senior Health Insurance Program (SHIIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No program-specific income or asset limits for core SHIIP counseling services, which are free and available to all Medicare beneficiaries. Counselors assist with applications for related low-income programs like Medicare Savings Programs and Extra Help, which have separate income/resource guidelines (specific dollar amounts and tables referenced in local sponsor materials, e.g., via https://www.mchalbia.com; families should contact counselors for current charts varying by household size)[5]",
    "asset_limits": "No asset limits for SHIIP itself. For assisted programs like Extra Help or Medicare Savings Programs, resources are evaluated (details on what counts/exempts provided by counselors; e.g., some personal assets exempt)[5]",
    "other_requirements": ["Must be a Medicare beneficiary (age 65+ or under 65 with disabilities)", "Iowa resident", "Open to those dually eligible for Medicare/Medicaid or with limited incomes, but no strict barriers for general counseling[1][3]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Free, objective, confidential one-on-one counseling, education, and assistance on Medicare options (Parts A/B, Advantage/C, Part D, Medigap); help enrolling/changing plans; applications for low-income aids (Medicaid, Medicare Savings, Extra Help); group presentations; fraud prevention via SMP; claim reviews; no direct financial aid or services provided[1][2][3][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Statewide 1-800-351-4664 or local sponsor sites (e.g., 712-794-5801 for St. Anthony, 712-264-6198 for Spencer, 641-932-1703 for Albia, 855-410-6222 for Milestones)", "Website: https://shiip.iowa.gov/ for info and local sponsor finder", "Email: shiip@iid.iowa.gov", "In-person: Local SHIIP sponsor sites (hospitals, area agencies on aging; find via website or phone)", "No formal application form; request appointment for counseling[1][2][4][5][6]"],
    "processing_time": "Immediate phone assistance available; in-person appointments scheduled upon request (typically quick, no formal processing)[1][2]",
    "waitlist": null,
    "forms": ["No specific SHIIP enrollment form; counselors assist with Medicare-related forms (e.g., Part D enrollment, Extra Help applications) during sessions[5]"],
    "documents": ["Medicare card", "Current insurance/plan details", "Prescription list", "Income/resource info if applying for low-income aids", "Social Security info for enrollment help; bring what you have for personalized counseling[2][4][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered statewide via network of local sponsors (hospitals like St. Anthony/Spencer, area agencies like Milestones, community sites); different local phone numbers, offices, and volunteer coordinators, but consistent services and standards[1][2][4][6]",
    "offices_or_providers": ["Local sponsor sites found via https://shiip.iowa.gov/ or 1-800-351-4664 (examples: St. Anthony Hospital, Spencer Hospital, Milestones AAA in Davenport/Ottumwa, Albia office)[2][4][5][6]"]
  },
  "official_source": "https://shiip.iowa.gov/",
  "gotchas": ["Not a direct benefits program—provides counseling/advocacy only, not payments or healthcare; does not sell plans or affiliate with insurers[1][6]", "Assists with low-income programs but eligibility for those is separate (people miss needing to provide income details)[5]", "Annual Medicare changes (e.g., Open Enrollment Oct 15-Dec 7); verify plan coverage by service location/zip[2][4][5]", "Under 65? Must have Medicare due to disability[1][3]", "Contact local sponsor for region-specific events/appointments, not just state line[1]"],
  "data_shape_notes": "no income test for counseling; statewide but locally sponsored with varying contact points; focuses on Medicare navigation rather than direct aid; assists with tiered low-income programs without owning their limits"
}

{
