{
  "name": "Iowa Legal Aid for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "Based on 125% of the Federal Poverty Guidelines (varies by household size and year; exact dollar amounts set annually by Iowa Legal Aid Board using LSC guidelines). Special grants allow higher limits for seniors or specific issues like elder law[5][8]. No means testing prohibition for denial based solely on income for those 60+[1].",
    "asset_limits": "Not specified for Iowa Legal Aid for Seniors program. Related Medicaid programs for seniors mention $2,000 limit for single individuals (home, car, household goods, burial funds exempt), but this is not directly for legal aid[2][4].",
    "other_requirements": ["Iowa resident", "Low-income (per 125% FPL guidelines)", "Legal issue in priority areas like elder law, housing, public benefits, family/safety[1][5][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal assistance including advice, counseling, representation on elder law issues (e.g., 60+ Elder Law, Disability, Housing, Taxes, Veterans’ Issues, public benefits, preventing legal problems via education/outreach). Provided by Iowa Legal Aid staff and volunteer lawyers[1][5][6]. No specific dollar amounts or hours stated.",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: 1-800-532-1275 (Mon-Fri 9am-4pm) or 1-800-532-1503[5][7]", "Online: https://www.iowalegalaid.org/ (apply anytime)[5][7]", "In-person: Offices open 8:30am-4:30pm (e.g., Iowa City: 1700 S. 1st Ave., Iowa City, IA 52240)[5]"],
    "processing_time": "Not specified in sources.",
    "waitlist": null,
    "forms": ["Online application form at https://www.iowalegalaid.org/[5][7]"],
    "documents": ["Proof of income, age, residency (prepare financial details as they may ask about circumstances for legal advice)[1][5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Accessible in each county throughout each planning and service area[1].",
    "regional_variations": "Local level consideration for priorities (e.g., disabilities, homelessness risk, guardianship); offices vary by location (e.g., Johnson County office in Iowa City)[1][5]. No specific wait time variations noted.",
    "offices_or_providers": ["Iowa City office example: 1700 S. 1st Ave., Iowa City, IA 52240; statewide offices via https://www.iowalegalaid.org/[5][7]"]
  },
  "official_source": "https://www.iowalegalaid.org/",
  "gotchas": ["Not automatic eligibility even if 60+; must meet income guidelines (125% FPL) unless special grant applies[5][8]", "Means testing prohibited for denial solely on income for 60+, but financial screening occurs[1]", "Priority for vulnerable groups (e.g., at risk of institutionalization, limited English); general low-income Iowans may be screened out[1]", "Confused with Elderly Waiver (Medicaid HCBS, age 65+, strict $2,901/month income & $2,000 assets for 2025); this is legal aid, not care services[2][3]", "Emergencies handled when offices open; call hotline for screening[5]"],
  "data_shape_notes": "No strict asset test or fixed dollar income caps listed (uses % FPL table by household size); special grants expand access for seniors beyond standard 125% FPL; priority-based rather than fixed benefits; statewide but local outreach/priorities vary; funded by LSC with elder-specific focus[1][5][8]"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; available to any resident regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Must be a resident or tenant of a long-term care facility in Iowa, including nursing facilities, assisted living programs, residential care facilities, or elder group homes.", "Also serves individuals enrolled in Iowa’s Home and Community-Based Services (HCBS) waiver programs (e.g., AIDS/HIV, Brain Injury, Children’s Mental Health, Elderly, Health and Disability, Intellectual Disability, Physical Disability).", "Exclusions for certain assisted living/residential care: acute stage of alcoholism/drug addiction/uncontrolled mental illness; under age 18; requires more than part-time/intermittent health-related care; unmanageable incontinence despite program; behavior placing others at risk.", "Family members, friends, or others can contact on behalf of residents."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigates complaints about conditions or treatment; resolves issues related to resident rights, facility policies, regulations, involuntary discharge, facility closure, substitute decision makers (e.g., power of attorney, guardian), resident/family councils; educates on self-advocacy, rights, and choosing facilities/managed care; provides information and assistance without cost.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Call statewide access line at 1-800-532-3213 (access code 878277# for prompts).", "Contact Local Long-Term Care Ombudsman (posted in facilities).", "Visit: https://hhs.iowa.gov/health-prevention/aging-services/ltcombudsman.", "Download brochures for more info: Long-Term Care Ombudsman Brochure or Resident Rights Brochure."],
    "processing_time": "Local Ombudsmen respond timely; investigation where not immediately possible.",
    "waitlist": null,
    "forms": ["No specific application form for services; contact directly to request assistance."],
    "documents": ["No documents required; provide details of concern/complaint verbally or in writing."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Limited to long-term care facilities and specified HCBS waiver programs statewide.",
    "regional_variations": "Each facility/program has a designated Local Long-Term Care Ombudsman; local ombudsmen organize by geographic area for timely response; contact info posted in facilities.",
    "offices_or_providers": ["Office of the State Long-Term Care Ombudsman within Iowa Department of Health and Human Services."]
  },
  "official_source": "https://hhs.iowa.gov/health-prevention/aging-services/ltcombudsman",
  "gotchas": ["Not a volunteer program for families to join (that's separate certification requiring training, background checks, no conflicts of interest); it's free advocacy for residents—call directly for help, no application barriers.", "Does not provide direct care/services, only advocacy and complaint resolution.", "Exclusions apply in some residential settings for high-need cases.", "Families can contact anytime, even pre-placement."],
  "data_shape_notes": "no income test; open to all long-term care residents statewide via local ombudsmen; advocacy-focused, not financial/service provision; volunteer ombudsman recruitment is separate process."
}
